// SPDX-License-Identifier: MIT
pragma solidity ^0.8.17;

import "../registry/ENS.sol";
import "../resolvers/profiles/INameResolver.sol";
import "../resolvers/profiles/IAddrResolver.sol";

/// @title Simplified UniversalResolver for local development
/// @notice This is a minimal implementation without CCIP-Read support
/// @dev Suitable for local Hardhat development only
contract UniversalResolver {
    ENS public immutable registry;

    // namehash('addr.reverse')
    bytes32 constant ADDR_REVERSE_NODE =
        0x91d1777781884d03a6757a803996e38de2a42967fb37eeaca72729271025a9e2;

    // Lookup table for hex encoding
    bytes32 constant lookup =
        0x3031323334353637383961626364656600000000000000000000000000000000;

    error ResolverNotFound();
    error ReverseAddressMismatch(string name, address expected, address actual);

    constructor(ENS _registry) {
        registry = _registry;
    }

    /// @notice Performs ENS reverse resolution for the supplied address
    /// @param lookupAddress The address bytes (20 bytes for ETH addresses)
    /// @param coinType The coin type (60 for ETH)
    /// @return name The resolved primary name
    /// @return resolver The resolver address for the primary name
    /// @return reverseResolver The resolver address for the reverse name
    function reverse(
        bytes calldata lookupAddress,
        uint256 coinType
    )
        public
        view
        returns (string memory name, address resolver, address reverseResolver)
    {
        return _reverse(lookupAddress, coinType);
    }

    /// @notice Performs ENS reverse resolution with gateway URLs (for viem/wagmi compatibility)
    /// @dev Gateways are ignored in this local implementation
    function reverseWithGateways(
        bytes calldata lookupAddress,
        uint256 coinType,
        string[] memory /* gateways */
    )
        external
        view
        returns (string memory name, address resolver, address reverseResolver)
    {
        return _reverse(lookupAddress, coinType);
    }

    /// @dev Internal reverse resolution logic
    function _reverse(
        bytes calldata lookupAddress,
        uint256 coinType
    )
        internal
        view
        returns (string memory name, address resolver, address reverseResolver)
    {
        // Only support ETH addresses (coinType 60) for simplicity
        require(coinType == 60 || coinType == 0, "Unsupported coin type");
        require(lookupAddress.length == 20, "Invalid address length");

        // Convert bytes to address
        address addr;
        assembly {
            addr := shr(96, calldataload(lookupAddress.offset))
        }

        // Get the reverse node for this address
        bytes32 reverseNode = _reverseNode(addr);

        // Find the resolver for the reverse node
        reverseResolver = registry.resolver(reverseNode);
        if (reverseResolver == address(0)) {
            return ("", address(0), address(0));
        }

        // Get the name from the reverse resolver
        try INameResolver(reverseResolver).name(reverseNode) returns (
            string memory resolvedName
        ) {
            name = resolvedName;
        } catch {
            return ("", address(0), reverseResolver);
        }

        if (bytes(name).length == 0) {
            return ("", address(0), reverseResolver);
        }

        // Get the forward resolver for the name
        bytes32 forwardNode = _namehash(name);
        resolver = registry.resolver(forwardNode);

        if (resolver == address(0)) {
            return (name, address(0), reverseResolver);
        }

        // Verify forward resolution matches (optional but recommended)
        try IAddrResolver(resolver).addr(forwardNode) returns (
            address payable forwardAddr
        ) {
            if (forwardAddr != addr) {
                // Forward resolution doesn't match - return empty
                return ("", address(0), reverseResolver);
            }
        } catch {
            // If forward resolution fails, still return the name
            // This allows names without forward records to work
        }

        return (name, resolver, reverseResolver);
    }

    /// @notice Resolve a name to an address
    /// @param name DNS-encoded name
    /// @param data The resolution calldata (e.g., addr(bytes32) call)
    /// @return result The encoded result
    /// @return resolver The resolver that provided the result
    function resolve(
        bytes calldata name,
        bytes calldata data
    ) external view returns (bytes memory result, address resolver) {
        // Decode the DNS-encoded name to get the node
        bytes32 node = _dnsNamehash(name);

        resolver = registry.resolver(node);
        if (resolver == address(0)) {
            revert ResolverNotFound();
        }

        // Forward the call to the resolver
        (bool success, bytes memory returnData) = resolver.staticcall(data);
        require(success, "Resolver call failed");

        return (returnData, resolver);
    }

    /// @dev Calculate the reverse node for an address
    function _reverseNode(address addr) internal pure returns (bytes32) {
        return
            keccak256(
                abi.encodePacked(ADDR_REVERSE_NODE, _sha3HexAddress(addr))
            );
    }

    /// @dev SHA3 of lowercase hex address
    function _sha3HexAddress(address addr) private pure returns (bytes32 ret) {
        assembly {
            for {
                let i := 40
            } gt(i, 0) {

            } {
                i := sub(i, 1)
                mstore8(i, byte(and(addr, 0xf), lookup))
                addr := div(addr, 0x10)
                i := sub(i, 1)
                mstore8(i, byte(and(addr, 0xf), lookup))
                addr := div(addr, 0x10)
            }
            ret := keccak256(0, 40)
        }
    }

    /// @dev Simple namehash for dot-separated names
    function _namehash(string memory name) internal pure returns (bytes32) {
        bytes32 node = 0x0;
        bytes memory nameBytes = bytes(name);

        if (nameBytes.length == 0) {
            return node;
        }

        // Process from right to left
        uint256 i = nameBytes.length;
        uint256 lastDot = nameBytes.length;

        while (i > 0) {
            i--;
            if (nameBytes[i] == ".") {
                node = keccak256(
                    abi.encodePacked(
                        node,
                        _labelHash(nameBytes, i + 1, lastDot)
                    )
                );
                lastDot = i;
            }
        }

        // Process the first label
        node = keccak256(
            abi.encodePacked(node, _labelHash(nameBytes, 0, lastDot))
        );

        return node;
    }

    /// @dev Hash a label from a name
    function _labelHash(
        bytes memory name,
        uint256 start,
        uint256 end
    ) private pure returns (bytes32) {
        bytes memory label = new bytes(end - start);
        for (uint256 i = start; i < end; i++) {
            label[i - start] = name[i];
        }
        return keccak256(label);
    }

    /// @dev Calculate namehash from DNS-encoded name
    function _dnsNamehash(
        bytes calldata name
    ) internal pure returns (bytes32 node) {
        node = 0x0;
        uint256 offset = 0;

        while (offset < name.length) {
            uint8 labelLength = uint8(name[offset]);
            if (labelLength == 0) break;

            bytes32 labelHash = keccak256(
                name[offset + 1:offset + 1 + labelLength]
            );
            node = keccak256(abi.encodePacked(node, labelHash));
            offset += 1 + labelLength;
        }

        return node;
    }
}
